use distributed_inference::acoustic::*;
use distributed_inference::buley::*;

fn main() {
    println!("============================================================");
    println!(" Topological Vacuum Architecture — Benchmark Suite");
    println!("============================================================");

    let mut engine = AcousticEngine::new();
    engine.set_voice(VoicePreset::sophia());

    // 1. Topological Function Siphoning
    println!(
        "
[1] Configuring Topological Function Siphoning..."
    );
    engine.register_function(5555, "trigger_topological_erasure");
    engine.register_function(8888, "open_vault");
    println!(" -> Registered trace 5555 to 'trigger_topological_erasure'");
    println!(" -> Registered trace 8888 to 'open_vault'");

    // 2. Context Injection
    println!(
        "
[2] Injecting Domain Context..."
    );
    let mut domain_terms = Vec::new();
    domain_terms.push((
        "neo_cortex",
        MoonshineVector {
            node_id: "neo_cortex".to_string(),
            bulk_state: vec![0.5, 0.6, 0.7],
            boundary_trace: 1234,
            dimension: 196884,
        },
    ));
    engine.inject_context(domain_terms);
    println!(" -> Pre-heated Amplituhedron with term 'neo_cortex'");

    // 3. Pre-heat with a complex YAML blueprint
    println!(
        "
[3] Pre-heating with YAML Acoustic Blueprint..."
    );
    let yaml_blueprint = r#"
bpm: 120
key: "C minor"
structure:
  - "verse"
  - "chorus"
spectral_brightness: 0.85
tags:
  - category: "language"
    value: "en-US"
    priority: 1
  - category: "task"
    value: "transcription"
    priority: 2
"#;
    engine
        .set_blueprint(yaml_blueprint)
        .expect("Failed to set blueprint");
    println!(
        " -> Blueprint injected successfully. Tags: {:?}",
        engine.current_blueprint.as_ref().unwrap().tags.len()
    );

    // 4. Pre-heat with Song Blueprint for multi-party mediation session
    println!(
        "
[4] Multi-Party Mediation Session Blueprint..."
    );
    let mediation_blueprint = r#"
bpm: 60
key: "Atonal"
structure:
  - "conflict"
  - "resolution"
spectral_brightness: 0.4
tags:
  - category: "speaker"
    value: "mediator_01"
    priority: 1
"#;
    engine
        .set_blueprint(mediation_blueprint)
        .expect("Failed to set mediation blueprint");
    println!(" -> Mediation blueprint active.");

    // 5. General Captions evolve across a multi-layered acoustic manifold
    println!(
        "
[5] Siphoning Multi-Layered Acoustic Manifold..."
    );
    // Simulate audio with trace that matches function 'trigger_topological_erasure'
    // To hit exactly trace 5555, we mock the output or just observe behavior.
    // Instead of mocking the exact trace from raw floats, we'll manually push a trace match
    let mut synthetic_audio_1 = Vec::new();
    for i in 0..100 {
        synthetic_audio_1.push((i as f32 * 0.1).sin());
    }

    // We'll just call siphon_audio normally
    let result_1 = engine.siphon_audio(&synthetic_audio_1, "phoneme_hello".to_string());
    println!(
        " -> Siphoned Layer 1: Trace = {}",
        result_1.vector.boundary_trace
    );

    // Let's force a function trigger by manually feeding a trace (via mocking the orchestrator or just observing the general caption output).
    // The last element in rich_stream will have the general caption.
    if let Some(last) = engine.rich_stream.last() {
        println!(" -> General Caption: {}", last.general_caption);
        println!(" -> Reasoning Chain: {:?}", last.reasoning_chain);
    }

    // 6. See the results of a "failed" siphon in the grounding log
    println!(
        "
[6] Buleyean Self-Verification (Failed Siphon)..."
    );
    let mut noisy_audio = Vec::new();
    // Structured but unrecognized acoustic geometry
    for i in 0..100 {
        let val = (i as f32 * 0.1).sin() + (i as f32 * 0.05).cos();
        noisy_audio.push(val);
    }
    let result_failure = engine.siphon_audio(&noisy_audio, "unrecognized_consensus".to_string());

    println!(
        " -> Failed Siphon Trace: {}",
        result_failure.vector.boundary_trace
    );
    println!(
        " -> Draft Accepted (SSD): {}",
        result_failure.is_draft_accepted
    );
    println!(" -> Failure Memory Size: {}", engine.failure_memory.len());

    if let Some(last) = engine.rich_stream.last() {
        println!(" -> Failed General Caption: {}", last.general_caption);
        if let Some(perception) = &last.perception {
            println!(
                " -> Perception Emotion: {}",
                perception.paralinguistics.emotion
            );
        }
    }

    println!(
        "
============================================================"
    );
    println!(" Benchmark Complete.");
    println!("============================================================");
}
